import heapq

def solve(nums: list[int], k: int) -> list[float]:
    if not nums or k == 0:
        return []

    small = []
    large = []
    delayed = {}
    small_size = 0
    large_size = 0

    def prune(heap):
        while heap:
            num = -heap[0] if heap is small else heap[0]
            if delayed.get(num, 0):
                heapq.heappop(heap)
                delayed[num] -= 1
                if delayed[num] == 0:
                    del delayed[num]
            else:
                break

    def make_balance():
        nonlocal small_size, large_size
        if small_size > large_size + 1:
            prune(small)
            val = -heapq.heappop(small)
            heapq.heappush(large, val)
            small_size -= 1
            large_size += 1
        elif small_size < large_size:
            prune(large)
            val = heapq.heappop(large)
            heapq.heappush(small, -val)
            large_size -= 1
            small_size += 1

    def insert(num):
        nonlocal small_size, large_size
        if not small or num <= -small[0]:
            heapq.heappush(small, -num)
            small_size += 1
        else:
            heapq.heappush(large, num)
            large_size += 1
        make_balance()

    def erase(num):
        nonlocal small_size, large_size
        delayed[num] = delayed.get(num, 0) + 1
        if num <= -small[0]:
            small_size -= 1
            if num == -small[0]:
                prune(small)
        else:
            large_size -= 1
            if large and num == large[0]:
                prune(large)
        make_balance()

    def get_median():
        prune(small)
        prune(large)
        if k % 2 == 1:
            return float(-small[0])
        else:
            return (-small[0] + large[0]) / 2.0

    res = []
    for i, num in enumerate(nums):
        insert(num)
        if i >= k:
            erase(nums[i - k])
        if i >= k - 1:
            res.append(get_median())
    return res
